import { create } from "zustand";
import { Chess, type Square } from "chess.js";

export type PlayerColor = "w" | "b";
export type ColorChoice = "white" | "random" | "black";
export type HintState = { level: 1 | 2; from: string; to: string } | null;

export type EvalPoint = {
  moveNumber: number;
  san: string;
  fen: string; // position AFTER this move
  fenBefore: string; // position BEFORE this move (for computing best-move SAN)
  byColor: PlayerColor;
  evalBefore: number | null; // centipawns, from white's perspective
  evalAfter: number | null;
  mateBefore: number | null;
  mateAfter: number | null;
  bestMoveBefore: string | null; // UCI of engine's suggested move, from the position before this move
  classification: MoveClass | null;
};

export type MoveClass =
  | "best"
  | "excellent"
  | "good"
  | "inaccuracy"
  | "mistake"
  | "blunder"
  | "book";

export type GamePhase = "setup" | "playing" | "finished";

export type AnalysisState = {
  evalCp: number | null;
  mate: number | null;
  bestMoveUci: string | null;
  bestMoveSan: string | null;
  pv: string[];
  depth: number;
  thinking: boolean;
};

export type AdviceState = {
  text: string;
  loading: boolean;
};

type GameStore = {
  phase: GamePhase;
  playerColor: PlayerColor;
  colorChoice: ColorChoice;
  elo: number; // opponent (Stockfish) strength
  game: Chess;
  fen: string;
  history: EvalPoint[];
  analysis: AnalysisState;
  advice: AdviceState;
  summary: { text: string; loading: boolean } | null;
  gameOverReason: string | null;
  hint: HintState;
  hintsRemaining: number;
  startGame: (choice: ColorChoice, elo: number) => void;
  resetToSetup: () => void;
  makeMove: (from: Square, to: Square, promotion?: string) => boolean;
  applyEngineMove: (uciMove: string) => void;
  setAnalysis: (partial: Partial<AnalysisState>) => void;
  pushEvalPoint: (point: EvalPoint) => void;
  setAdvice: (partial: Partial<AdviceState>) => void;
  setSummary: (partial: { text: string; loading: boolean } | null) => void;
  checkGameOver: () => void;
  useHint: () => void;
  undoLastFullMove: () => void;
  resign: () => void;
};

export const useGameStore = create<GameStore>((set, get) => ({
  phase: "setup",
  playerColor: "w",
  colorChoice: "white",
  elo: 1200,
  game: new Chess(),
  fen: new Chess().fen(),
  history: [],
  analysis: {
    evalCp: 0,
    mate: null,
    bestMoveUci: null,
    bestMoveSan: null,
    pv: [],
    depth: 0,
    thinking: false,
  },
  advice: { text: "", loading: false },
  summary: null,
  gameOverReason: null,
  hint: null,
  hintsRemaining: 6,
  startGame: (choice, elo) => {
    const resolved: PlayerColor =
      choice === "white"
        ? "w"
        : choice === "black"
          ? "b"
          : Math.random() < 0.5
            ? "w"
            : "b";
    const game = new Chess();
    set({
      phase: "playing",
      playerColor: resolved,
      colorChoice: choice,
      elo,
      game,
      fen: game.fen(),
      history: [],
      advice: { text: "", loading: false },
      summary: null,
      gameOverReason: null,
      analysis: {
        evalCp: 0,
        mate: null,
        bestMoveUci: null,
        bestMoveSan: null,
        pv: [],
        depth: 0,
        thinking: false,
      },
      hint: null,
      hintsRemaining: 6,
    });
  },

  makeMove: (from, to, promotion = "q") => {
    const { game } = get();
    try {
      const move = game.move({ from, to, promotion });
      if (!move) return false;
      set({ fen: game.fen(), hint: null }); // เคลียร์คำใบ้เก่าทุกครั้งที่มีการเดินจริง
      get().checkGameOver();
      return true;
    } catch {
      return false;
    }
  },
  resetToSetup: () => set({ phase: "setup" }),

  applyEngineMove: (uciMove) => {
    const { game } = get();
    const from = uciMove.slice(0, 2) as Square;
    const to = uciMove.slice(2, 4) as Square;
    const promotion = uciMove.length > 4 ? uciMove.slice(4) : undefined;
    try {
      game.move({ from, to, promotion });
      set({ fen: game.fen(), hint: null });
      get().checkGameOver();
    } catch {
      // ignore
    }
  },

  useHint: () => {
    const { hint, hintsRemaining, analysis, phase } = get();
    if (phase !== "playing" || hintsRemaining <= 0) return;

    // ลองใช้ bestMoveUci ก่อน ถ้าไม่มีให้ดึงจาก Principal Variation (pv) ตาแรก
    const bestUci = analysis.bestMoveUci || analysis.pv?.[0];

    // ถ้า Stockfish ยังวิเคราะห์ไม่เสร็จจริง ๆ ให้ข้ามไป (ยังไม่ตัดจำนวน hintsRemaining)
    if (!bestUci || bestUci.length < 4) return;

    const from = bestUci.slice(0, 2);
    const to = bestUci.slice(2, 4);

    // คำใบ้ใหม่ (ตำแหน่งเปลี่ยนไปแล้ว หรือยังไม่เคยขอ) เริ่มที่ระดับ 1
    if (!hint || hint.from !== from || hint.to !== to) {
      set({ hint: { level: 1, from, to }, hintsRemaining: hintsRemaining - 1 });
      return;
    }

    // เดิมอยู่ระดับ 1 แล้ว กดซ้ำ = อัปเกรดเป็นระดับ 2
    if (hint.level === 1) {
      set({ hint: { level: 2, from, to }, hintsRemaining: hintsRemaining - 1 });
    }
  },

  undoLastFullMove: () => {
    const { game, phase, playerColor } = get();
    if (phase !== "playing") return;
    const verbose = game.history({ verbose: true });
    if (verbose.length === 0) return;

    // ถ้าตอนนี้เป็นตาผู้เล่น (แปลว่า AI เพิ่งเดินตอบ) ต้องย้อน 2 ครึ่งตา
    // ถ้าเป็นตา AI (แปลว่าผู้เล่นเพิ่งเดิน AI ยังไม่ทันตอบ) ย้อนแค่ 1
    const pliesToUndo =
      game.turn() === playerColor ? Math.min(2, verbose.length) : 1;
    for (let i = 0; i < pliesToUndo; i++) game.undo();

    set((s) => ({
      fen: game.fen(),
      history: s.history.slice(0, Math.max(0, s.history.length - pliesToUndo)),
      hint: null,
      advice: { text: "", loading: false },
    }));
  },

  resign: () => {
    if (get().phase !== "playing") return;
    set({ phase: "finished", gameOverReason: "ยอมแพ้" });
  },

  setAnalysis: (partial) =>
    set((s) => ({ analysis: { ...s.analysis, ...partial } })),

  pushEvalPoint: (point) => set((s) => ({ history: [...s.history, point] })),

  setAdvice: (partial) => set((s) => ({ advice: { ...s.advice, ...partial } })),

  setSummary: (val) => set({ summary: val }),

  checkGameOver: () => {
    const { game } = get();
    if (game.isGameOver()) {
      let reason = "จบเกม";
      if (game.isCheckmate()) reason = "รุกฆาต";
      else if (game.isStalemate()) reason = "หมดสิทธิ์เดิน (Stalemate)";
      else if (game.isThreefoldRepetition()) reason = "เดินซ้ำ 3 ครั้ง";
      else if (game.isInsufficientMaterial()) reason = "หมากไม่พอรุกฆาต";
      else if (game.isDraw()) reason = "เสมอ";
      set({ phase: "finished", gameOverReason: reason });
    }
  },
}));
